create extension if not exists pgcrypto;
create table if not exists pages (id uuid primary key default gen_random_uuid(), slug text unique not null, title text not null, seo_title text, seo_description text, is_published boolean default true, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists page_sections (id uuid primary key default gen_random_uuid(), page_slug text references pages(slug) on delete cascade, section_key text unique not null, section_name text not null, section_type text not null, order_index int default 0, is_active boolean default true, settings jsonb default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists section_fields (id uuid primary key default gen_random_uuid(), section_id uuid references page_sections(id) on delete cascade, field_key text not null, field_label text not null, field_type text not null check (field_type in ('text','textarea','richtext','image','video','file','url','color','number','boolean','date','select','json')), field_value text, field_json jsonb, order_index int default 0, created_at timestamptz default now(), updated_at timestamptz default now(), unique(section_id,field_key));
create table if not exists theme_settings (id uuid primary key default gen_random_uuid(), key text unique not null, value text, value_json jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists media_assets (id uuid primary key default gen_random_uuid(), title text not null, description text, file_url text not null, file_type text not null, mime_type text, alt_text text, storage_path text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists navigation_items (id uuid primary key default gen_random_uuid(), location text not null check (location in ('main_menu','fiti_menu','footer_menu')), label text not null, url text not null, page_slug text, order_index int default 0, is_active boolean default true, is_external boolean default false, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists social_links (id uuid primary key default gen_random_uuid(), platform text not null, label text, url text not null, is_active boolean default true, order_index int default 0);
create table if not exists content_revisions (id uuid primary key default gen_random_uuid(), content_type text not null, content_id uuid, previous_value jsonb, new_value jsonb, changed_by uuid, created_at timestamptz default now());
create table if not exists site_settings (id uuid primary key default gen_random_uuid(), key text unique not null, value jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists timeline (id uuid primary key default gen_random_uuid(), year text, title text, description text, order_index int, created_at timestamptz default now());
create table if not exists projects (id uuid primary key default gen_random_uuid(), title text, description text, image_url text, link text, featured boolean default false, created_at timestamptz default now());
create table if not exists impact_stats (id uuid primary key default gen_random_uuid(), label text, value int, suffix text, order_index int);
create table if not exists gallery (id uuid primary key default gen_random_uuid(), title text, image_url text, category text, description text, created_at timestamptz default now());
create table if not exists news (id uuid primary key default gen_random_uuid(), title text, slug text unique, summary text, content text, image_url text, category text, published boolean default false, created_at timestamptz default now());
create table if not exists partners (id uuid primary key default gen_random_uuid(), name text, logo_url text, category text, link text, show_on_home boolean default true, show_on_fiti boolean default false, created_at timestamptz default now());
create table if not exists fiti_editions (id uuid primary key default gen_random_uuid(), year text, theme text, dates text, locations text, countries text, description text, poster_url text, active boolean default false, created_at timestamptz default now());
create table if not exists fiti_program (id uuid primary key default gen_random_uuid(), edition_id uuid references fiti_editions(id), date date, time text, title text, company text, country text, venue text, category text, synopsis text, duration text, age_rating text, image_url text, reservation_link text, created_at timestamptz default now());
create table if not exists fiti_companies (id uuid primary key default gen_random_uuid(), edition_id uuid references fiti_editions(id), name text, country text, city text, description text, image_url text, social_link text, created_at timestamptz default now());
create table if not exists fiti_workshops (id uuid primary key default gen_random_uuid(), edition_id uuid references fiti_editions(id), title text, trainer text, date date, time text, venue text, vacancies text, target_audience text, description text, registration_link text, created_at timestamptz default now());
create table if not exists contact_messages (id uuid primary key default gen_random_uuid(), name text, email text, phone text, subject text, message text, status text default 'Novo', created_at timestamptz default now());
create table if not exists fiti_applications (id uuid primary key default gen_random_uuid(), type text, company_name text, country text, city text, contact_person text, email text, phone text, show_title text, synopsis text, duration text, team_size text, technical_needs text, video_link text, portfolio_link text, notes text, status text default 'Novo', created_at timestamptz default now());
alter table pages enable row level security;alter table page_sections enable row level security;alter table section_fields enable row level security;alter table theme_settings enable row level security;alter table media_assets enable row level security;alter table navigation_items enable row level security;alter table social_links enable row level security;alter table content_revisions enable row level security;alter table contact_messages enable row level security;alter table fiti_applications enable row level security;
create policy "Public read published pages" on pages for select using (is_published=true);
create policy "Public read active sections" on page_sections for select using (is_active=true);
create policy "Public read section fields" on section_fields for select using (true);
create policy "Public read theme" on theme_settings for select using (true);
create policy "Public read navigation" on navigation_items for select using (is_active=true);
create policy "Public read social links" on social_links for select using (is_active=true);
create policy "Public read media" on media_assets for select using (true);
create policy "Admin write pages" on pages for all using (auth.role()='authenticated') with check (auth.role()='authenticated');
create policy "Admin write sections" on page_sections for all using (auth.role()='authenticated') with check (auth.role()='authenticated');
create policy "Admin write fields" on section_fields for all using (auth.role()='authenticated') with check (auth.role()='authenticated');
create policy "Admin write theme" on theme_settings for all using (auth.role()='authenticated') with check (auth.role()='authenticated');
create policy "Admin write media" on media_assets for all using (auth.role()='authenticated') with check (auth.role()='authenticated');
create policy "Admin read forms" on contact_messages for select using (auth.role()='authenticated');
create policy "Admin update forms" on contact_messages for update using (auth.role()='authenticated');
create policy "Public insert contact" on contact_messages for insert with check (true);
create policy "Admin read applications" on fiti_applications for select using (auth.role()='authenticated');
create policy "Public insert applications" on fiti_applications for insert with check (true);
